mapper.select:
select s.*, c.name as clazz_name from student s left join clazz c on s.clazz_id = c.id
and s.name like concat('%', #{name}, '%')
and s.degree = #{degree}
and s.clazz_id = #{clazzId}
order by s.update_time desc
